import React, { useEffect, useState } from 'react';
import { View, Text, Button, AsyncStorage } from 'react-native';
import { authorize, refresh } from 'react-native-app-auth';

const config = {
  issuer: 'https://your-oauth-server.com',
  clientId: 'your_client_id',
  clientSecret: 'your_client_secret', // Store securely, not in plaintext
  redirectUrl: 'com.yourapp:/oauth2redirect',
  scopes: ['openid', 'profile', 'email'],
};

const App = () => {
  const [authState, setAuthState] = useState(null);

  const authenticate = async () => {
    try {
      const result = await authorize(config);
      setAuthState(result);
      await AsyncStorage.setItem('authState', JSON.stringify(result));
    } catch (error) {
      console.error('Authentication error:', error);
    }
  };

  const refreshToken = async () => {
    if (authState) {
      try {
        const refreshedState = await refresh(config, {
          refreshToken: authState.refreshToken,
        });
        setAuthState(refreshedState);
        await AsyncStorage.setItem('authState', JSON.stringify(refreshedState));
      } catch (error) {
        console.error('Token refresh error:', error);
      }
    }
  };

  useEffect(() => {
    const loadAuthState = async () => {
      const storedAuthState = await AsyncStorage.getItem('authState');
      if (storedAuthState) {
        setAuthState(JSON.parse(storedAuthState));
      }
    };
    loadAuthState();
  }, []);

  return (
    <View>
      <Text>{authState ? `Welcome! ${authState.accessToken}` : 'Please log in'}</Text>
      <Button title="Login" onPress={authenticate} />
      <Button title="Refresh Token" onPress={refreshToken} />
    </View>
  );
};

export default App;